const QUESTIONS = [
  { id: "q0001", topic: "communication:general", level: "A2", difficulty: 4, type: "tiles", q: "Составь:\n«Я участвую в курсе.»", words: ["Ich", "nehme", "an", "dem", "Kurs", "teil."], explain: "teilnehmen — отдел. teil- уходит в конец. teilnehmen an + Dat." },
  { id: "q0002", topic: "communication:general", level: "A2", difficulty: 4, type: "tiles", q: "Составь:\n«Это предложение очень выгодное.»", words: ["Das", "Angebot", "ist", "sehr", "günstig."], explain: "После sein — без окончания. das Angebot (n)." },
  { id: "q0003", topic: "communication:greetings", level: "A2", difficulty: 4, type: "tiles", q: "Составь:\n«Сердечно приветствуем в Берлине!»", words: ["Herzlich", "willkommen", "in", "Berlin!"], explain: "Стандартная формула приветствия. in + Dat (im/in Berlin)." },
  { id: "q0004", topic: "grammar:cases", level: "A2", difficulty: 4, type: "fill", q: "Pl от \"der Gruß\"?", ans: "die Grüße", altAns: ["Grüße"], hint: "+ Umlaut, +e", explain: "der Gruß → die Grüße (u→ü, +e)." },
  { id: "q0005", topic: "grammar:articles", level: "A2", difficulty: 4, type: "fill", q: "Какой артикль? \"___ Kunst\"", ans: "die", hint: "женский род", explain: "die Kunst (f). Pl: die Künste." },
  { id: "q0006", topic: "grammar:articles", level: "A2", difficulty: 4, type: "fill", q: "Какой артикль? \"___ Angebot\" (предложение)", ans: "das", hint: "средний род", explain: "das Angebot (n). От anbieten." },
  { id: "q0007", topic: "grammar:articles", level: "A2", difficulty: 4, type: "fill", q: "От какого слова образовано «herzlich»?", ans: "Herz", altAns: ["das Herz", "Herz"], hint: "сердце", explain: "Herz + -lich = herzlich. Суффикс -lich образует прилагательные." },
  { id: "q0008", topic: "grammar:articles", level: "A2", difficulty: 4, type: "fill", q: "От какого слова «täglich»?", ans: "Tag", altAns: ["der Tag", "Tag"], hint: "день", explain: "Tag + -lich = täglich (с умлаутом)." },
  { id: "q0009", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «laden» в Präsens:", ans: ["lade", "lädst", "lädt", "laden", "ladet", "laden"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "Unregelmäßig: a→ä у du и er. ich lade, du lädst, er lädt." },
  { id: "q0010", topic: "quantity:cardinal", level: "A1", difficulty: 1, type: "mc", q: "Как пишется число 30?", opts: ["dreizig", "dreißig", "dreizehn", "drießig"], ans: 1, explain: "30 — dreißig. Через ß, не z." },
  { id: "q0011", topic: "quantity:cardinal", level: "A1", difficulty: 1, type: "mc", q: "Что означает «halb drei»?", opts: ["3 часа", "2:30", "3:30", "половина четвёртого"], ans: 1, explain: "halb drei = половина третьего = 2:30. В немецком смотрят на СЛЕДУЮЩИЙ час." },
  { id: "q0012", topic: "quantity:cardinal", level: "A1", difficulty: 1, type: "mc", q: "Какой предлог для дней?", opts: ["um", "in", "am", "auf"], ans: 2, explain: "am Montag, am Dienstag... am = an + dem (Dativ)." },
  { id: "q0013", topic: "quantity:cardinal", level: "A1", difficulty: 1, type: "mc", q: "Какой предлог для времени (часов)?", opts: ["am", "um", "in", "bei"], ans: 1, explain: "um 5 Uhr — в 5 часов." },
  { id: "q0014", topic: "quantity:cardinal", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «В понедельник в 5 часов.»", words: ["Am", "Montag", "um", "5", "Uhr."], explain: "am + день, um + время." },
  { id: "q0015", topic: "quantity:cardinal", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"Es ist ___ drei.\" (2:30)", ans: "halb", hint: "половина", explain: "halb drei = 2:30. На следующий час." },
  { id: "q0016", topic: "quantity:cardinal", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"viertel ___ zwölf\" (12:15)", ans: "nach", hint: "после полудня", explain: "viertel nach zwölf = четверть первого = 12:15." },
  { id: "q0017", topic: "phonetics:rules", level: "A1", difficulty: 1, type: "mc", q: "Как читается «ei» в слове «mein»?", opts: ["[эй]", "[ай]", "[и]", "[е]"], ans: 1, explain: "ei, ai → [ай]. mein = [майн]." },
  { id: "q0018", topic: "phonetics:rules", level: "A1", difficulty: 1, type: "mc", q: "Как читается «ie» в слове «sieben»?", opts: ["[ие]", "[й]", "[и:]", "[ай]"], ans: 2, explain: "ie → [и:] (долгое и). sieben = [зибэн]." },
  { id: "q0019", topic: "phonetics:rules", level: "A1", difficulty: 1, type: "mc", q: "Как читается «eu» в слове «neun»?", opts: ["[еу]", "[э]", "[ой]", "[у]"], ans: 2, explain: "eu, äu → [ой]. neun = [нойн]." },
  { id: "q0020", topic: "phonetics:rules", level: "A1", difficulty: 1, type: "mc", q: "Как читается «sch» в «Schule»?", opts: ["[сч]", "[ш]", "[ск]", "[щ]"], ans: 1, explain: "sch → [ш]. Schule = [шулэ]." },
  { id: "q0021", topic: "phonetics:rules", level: "A1", difficulty: 1, type: "mc", q: "Как читается «ch» в слове «ich»?", opts: ["[х] — ach-Laut", "[к]", "[хь] — ich-Laut", "[ш]"], ans: 2, explain: "ch после e/i/ei/ä/ö/ü → [хь] (ich-Laut). ich = [ихь]." },
  { id: "q0022", topic: "phonetics:rules", level: "A1", difficulty: 1, type: "mc", q: "Как читается «ch» в слове «machen»?", opts: ["[хь]", "[к]", "[х] — ach-Laut", "[ш]"], ans: 2, explain: "ch после a/o/u/au → [х] (ach-Laut). machen = [махэн]." },
  { id: "q0023", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Ты любишь готовить?»", words: ["Kochst", "du", "gern?"], explain: "Verb + gern = «любить (делать)». Ja/Nein-Frage: Verb на 1-й позиции." },
  { id: "q0024", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "Präteritum от «sein» для «ich»?", ans: "war", hint: "был", explain: "ich war (Präteritum)." },
  { id: "q0025", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Я не могу прийти.»", words: ["Ich", "kann", "nicht", "kommen."], explain: "Modalverb на 2-й позиции, Infinitiv в конец." },
  { id: "q0026", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Я хочу учить немецкий.»", words: ["Ich", "will", "Deutsch", "lernen."], explain: "wollen на 2-й позиции, Infinitiv (lernen) в конце." },
  { id: "q0027", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"Ich ___ Deutsch lernen.\" (хочу)", ans: "will", hint: "wollen — ich", explain: "ich will. Modalverb." },
  { id: "q0028", topic: "grammar:modal", level: "A2", difficulty: 4, type: "fill", q: "sollen или müssen?\n\"Ich ___ schlafen.\" (сам устал)", ans: "muss", hint: "обязательство изнутри", explain: "müssen — обязательство ИЗНУТРИ / объективная необходимость." },
  { id: "q0029", topic: "grammar:modal", level: "A2", difficulty: 4, type: "fill", q: "sollen или müssen?\n\"Du ___ nicht lügen.\" (тебе говорят)", ans: "sollst", hint: "обязательство извне", explain: "sollen — обязательство ИЗВНЕ. Du sollst nicht lügen." },
  { id: "q0030", topic: "grammar:modal", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «können» в Präsens:", ans: ["kann", "kannst", "kann", "können", "könnt", "können"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "ich = er (kann). Modalverb." },
  { id: "q0031", topic: "grammar:modal", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «wollen» в Präsens:", ans: ["will", "willst", "will", "wollen", "wollt", "wollen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "ich = er (will)." },
  { id: "q0032", topic: "grammar:modal", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «müssen» в Präsens:", ans: ["muss", "musst", "muss", "müssen", "müsst", "müssen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "ich = er (muss)." },
  { id: "q0033", topic: "grammar:modal", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «dürfen» в Präsens:", ans: ["darf", "darfst", "darf", "dürfen", "dürft", "dürfen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "ich = er (darf)." },
  { id: "q0034", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Я забираю тебя в 7 часов.»", words: ["Ich", "hole", "dich", "um", "7", "Uhr", "ab."], explain: "abholen — отделяемая. ab- уходит в конец." },
  { id: "q0035", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"Er ___ Pizza.\" (есть)", ans: "isst", hint: "essen — er", explain: "essen → er isst (e→i)." },
  { id: "q0036", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"Du ___ schnell.\" (брать)", ans: "nimmst", hint: "nehmen — du", explain: "nehmen → du nimmst (h уходит, e→i, m→mm)." },
  { id: "q0037", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "wissen или kennen? \"Ich ___ ihn gut.\" (его)", ans: "kenne", hint: "знать человека", explain: "kennen — знать человека. wissen — знать факт." },
  { id: "q0038", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "wissen или kennen? \"Ich ___, wo er wohnt.\"", ans: "weiß", hint: "знать факт", explain: "wissen — знать факт. Unregel: ich weiß." },
  { id: "q0039", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "vermissen или verlieren?\n\"Ich ___ meinen Schlüssel.\" (потерял)", ans: "verliere", altAns: ["habe verloren"], hint: "о предмете", explain: "verlieren — терять (предмет). vermissen — скучать." },
  { id: "q0040", topic: "grammar:cases", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Я работаю в офисе.»", words: ["Ich", "arbeite", "im", "Büro."], explain: "im = in + dem (Dat). Wo? — Dativ." },
  { id: "q0041", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «sein» в Präsens:", ans: ["bin", "bist", "ist", "sind", "seid", "sind"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "Самый неправильный глагол. Учи наизусть." },
  { id: "q0042", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «haben» в Präsens:", ans: ["habe", "hast", "hat", "haben", "habt", "haben"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "du hast / er hat — без b!" },
  { id: "q0043", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «nehmen» в Präsens:", ans: ["nehme", "nimmst", "nimmt", "nehmen", "nehmt", "nehmen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "du/er: nimm- (h уходит, e→i)." },
  { id: "q0044", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «sprechen» в Präsens:", ans: ["spreche", "sprichst", "spricht", "sprechen", "sprecht", "sprechen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "e→i в du/er." },
  { id: "q0045", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «schlafen» в Präsens:", ans: ["schlafe", "schläfst", "schläft", "schlafen", "schlaft", "schlafen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "a→ä в du/er." },
  { id: "q0046", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «sehen» в Präsens:", ans: ["sehe", "siehst", "sieht", "sehen", "seht", "sehen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "e→ie в du/er. siehst, sieht." },
  { id: "q0047", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «essen» в Präsens:", ans: ["esse", "isst", "isst", "essen", "esst", "essen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "du/er совпадают: isst." },
  { id: "q0048", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «werfen» в Präsens:", ans: ["werfe", "wirfst", "wirft", "werfen", "werft", "werfen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "e→i: du wirfst, er wirft." },
  { id: "q0049", topic: "grammar:verbs", level: "A2", difficulty: 3, type: "conj", q: "Проспрягай «fangen» в Präsens:", ans: ["fange", "fängst", "fängt", "fangen", "fangt", "fangen"], pronouns: ["ich", "du", "er/sie/es", "wir", "ihr", "sie/Sie"], explain: "a→ä: du fängst, er fängt." },
  { id: "q0050", topic: "grammar:verbs", level: "A1", difficulty: 1, type: "mc", q: "Partizip II от «sehen»?", opts: ["geseht", "gesehen", "sehte", "sah"], ans: 1, explain: "sehen — Unregel. Part II: gesehen (с haben)." },
  { id: "q0051", topic: "grammar:verbs", level: "A1", difficulty: 1, type: "mc", q: "Präteritum от «bleiben»?", opts: ["bleibte", "blieb", "blei", "geblieben"], ans: 1, explain: "bleiben → blieb / geblieben (с sein)." },
  { id: "q0052", topic: "grammar:verbs", level: "A1", difficulty: 1, type: "mc", q: "Какое вспомогательное у «fliegen» в Perfekt?", opts: ["haben", "sein", "werden", "müssen"], ans: 1, explain: "Глаголы движения → sein. Ich bin geflogen." },
  { id: "q0053", topic: "grammar:cases", level: "A2", difficulty: 4, type: "fill", q: "Pl от \"das Kind\"?", ans: "die Kinder", altAns: ["Kinder"], hint: "+er", explain: "das Kind → die Kinder." },
  { id: "q0054", topic: "grammar:cases", level: "A2", difficulty: 4, type: "fill", q: "Pl от \"der Vater\"?", ans: "die Väter", altAns: ["Väter"], hint: "+ Umlaut", explain: "der Vater → die Väter (a→ä)." },
  { id: "q0055", topic: "grammar:cases", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Холодильник на кухне.»", words: ["Der", "Kühlschrank", "ist", "in", "der", "Küche."], explain: "Wo? + Dat. in der Küche (f, Dat)." },
  { id: "q0056", topic: "grammar:cases", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «У меня есть собака.»", words: ["Ich", "habe", "einen", "Hund."], explain: "haben + Akk. der Hund (m) → einen Hund." },
  { id: "q0057", topic: "grammar:articles", level: "A2", difficulty: 4, type: "fill", q: "Какой артикль? \"___ Küche\" (кухня)", ans: "die", hint: "женский род", explain: "die Küche (f)." },
  { id: "q0058", topic: "grammar:articles", level: "A2", difficulty: 4, type: "fill", q: "Какой артикль? \"___ Auto\" (машина)", ans: "das", hint: "средний род", explain: "das Auto (n)." },
  { id: "q0059", topic: "grammar:articles", level: "A2", difficulty: 4, type: "fill", q: "Какой артикль? \"___ Hund\" (собака)", ans: "der", hint: "мужской род", explain: "der Hund (m)." },
  { id: "q0060", topic: "grammar:adjectives", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Квартира маленькая, но красивая.»", words: ["Die", "Wohnung", "ist", "klein,", "aber", "schön."], explain: "После sein — без окончания. aber = но." },
  { id: "q0061", topic: "grammar:adjectives", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «У меня большая собака.»", words: ["Ich", "habe", "einen", "großen", "Hund."], explain: "m, Akk → einen + großen (m Akk → -en)." },
  { id: "q0062", topic: "grammar:adjectives", level: "A2", difficulty: 4, type: "fill", q: "Антоним к «groß»?", ans: "klein", hint: "противоположное", explain: "groß ↔ klein." },
  { id: "q0063", topic: "grammar:adjectives", level: "A2", difficulty: 4, type: "fill", q: "Антоним к «teuer»?", ans: "billig", altAns: ["günstig"], hint: "↔ дорогой", explain: "teuer ↔ billig / günstig." },
  { id: "q0064", topic: "grammar:adjectives", level: "A2", difficulty: 4, type: "fill", q: "Окончание: «ein groß___ Haus» (n, Nom)", ans: "es", hint: "n с ein → -es", explain: "ein großes Haus (n)." },
  { id: "q0065", topic: "grammar:adjectives", level: "A2", difficulty: 4, type: "fill", q: "Окончание: «die schön___ Frau» (f, Nom)", ans: "e", hint: "f с der → -e", explain: "die schöne Frau." },
  { id: "q0066", topic: "grammar:adjectives", level: "A1", difficulty: 1, type: "mc", q: "schön или schon — «красивый»?", opts: ["schon", "schön", "оба", "ни одно"], ans: 1, explain: "schön = красивый. schon = уже (наречие)." },
  { id: "q0067", topic: "grammar:particles", level: "A1", difficulty: 1, type: "mc", q: "Шкала частоты: что чаще всего?", opts: ["selten", "manchmal", "oft", "immer"], ans: 3, explain: "immer → oft → manchmal → selten → nie." },
  { id: "q0068", topic: "grammar:particles", level: "A1", difficulty: 1, type: "mc", q: "morgen или der Morgen — «завтра»?", opts: ["der Morgen", "morgen (со строчной)", "оба", "ни одно"], ans: 1, explain: "morgen (наречие) = завтра. Morgen (с заглавной, m) = утро." },
  { id: "q0069", topic: "grammar:wordorder", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Завтра я работаю.»", words: ["Morgen", "arbeite", "ich."], explain: "Наречие в начале → инверсия: Verb + Subjekt. Morgen со строчной (правда, в начале предложения с заглавной — но это просто 1-я буква)." },
  { id: "q0070", topic: "communication:greetings", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"Bis ___!\" (До скорого)", ans: "gleich", hint: "сейчас, тут же", explain: "Bis gleich! — До скорого / Скоро увидимся." },
  { id: "q0071", topic: "grammar:adjectives", level: "A2", difficulty: 4, type: "fill", q: "Антоним «schnell»?", ans: "langsam", hint: "противоположное", explain: "schnell ↔ langsam." },
  { id: "q0072", topic: "grammar:pronouns", level: "A1", difficulty: 1, type: "mc", q: "Akkusativ от «ich»?", opts: ["mir", "mich", "mein", "ich"], ans: 1, explain: "ich → mich (Akk) / mir (Dat)." },
  { id: "q0073", topic: "grammar:pronouns", level: "A1", difficulty: 1, type: "mc", q: "Dativ от «du»?", opts: ["dich", "dein", "dir", "du"], ans: 2, explain: "du → dich (Akk) / dir (Dat)." },
  { id: "q0074", topic: "grammar:pronouns", level: "A1", difficulty: 1, type: "mc", q: "Dativ от «er»?", opts: ["ihn", "ihm", "ihr", "ihnen"], ans: 1, explain: "er → ihn (Akk) / ihm (Dat)." },
  { id: "q0075", topic: "grammar:pronouns", level: "A1", difficulty: 1, type: "mc", q: "Dativ от «es»?", opts: ["es", "ihm", "ihr", "ihnen"], ans: 1, explain: "⚠ es в Dat → ihm, не ihr! Ловушка." },
  { id: "q0076", topic: "grammar:pronouns", level: "A1", difficulty: 1, type: "mc", q: "Dativ от «sie» (она)?", opts: ["sie", "ihn", "ihm", "ihr"], ans: 3, explain: "sie (она) → sie (Akk) / ihr (Dat)." },
  { id: "q0077", topic: "grammar:pronouns", level: "A1", difficulty: 1, type: "mc", q: "«mein» или «meine» с «Wohnung» (f)?", opts: ["mein", "meine", "meinen", "meinem"], ans: 1, explain: "f → +e: meine Wohnung." },
  { id: "q0078", topic: "grammar:pronouns", level: "A1", difficulty: 1, type: "mc", q: "«mein» или «meine» с «Buch» (n)?", opts: ["mein", "meine", "meinen", "meinem"], ans: 0, explain: "n → без окончания: mein Buch." },
  { id: "q0079", topic: "grammar:pronouns", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"Ich wasche ___\" (моюсь)", ans: "mich", hint: "себя, Akk", explain: "ich → mich. Akkusativ — действие на себя." },
  { id: "q0080", topic: "grammar:pronouns", level: "A2", difficulty: 4, type: "fill", q: "Вставь: \"Ich wasche ___ die Hände\" (себе руки)", ans: "mir", hint: "себе, Dat", explain: "ich → mir. Dativ — кому?" },
  { id: "q0081", topic: "grammar:pronouns", level: "A2", difficulty: 4, type: "fill", q: "Возвратное для er/sie/es в Akk?", ans: "sich", hint: "всегда одно слово", explain: "Er/sie/es и sie/Sie → всегда sich." },
  { id: "q0082", topic: "grammar:cases", level: "A1", difficulty: 1, type: "mc", q: "Какой вопрос для Akkusativ?", opts: ["Wer?", "Wem?", "Wen?", "Wo?"], ans: 2, explain: "Akk → Wen? Was?" },
  { id: "q0083", topic: "grammar:cases", level: "A1", difficulty: 1, type: "mc", q: "Какой вопрос для Dativ?", opts: ["Wer?", "Wem?", "Wen?", "Wo?"], ans: 1, explain: "Dat → Wem?" },
  { id: "q0084", topic: "grammar:cases", level: "A1", difficulty: 1, type: "mc", q: "«Wohin?» спрашивает о...", opts: ["месте (где?)", "направлении (куда?)", "источнике (откуда?)", "времени"], ans: 1, explain: "Wohin? = куда? (направление, + Akk)." },
  { id: "q0085", topic: "grammar:cases", level: "A1", difficulty: 1, type: "mc", q: "«Wo?» использует какой падеж с предлогом?", opts: ["Nom", "Akk", "Dat", "никакой"], ans: 2, explain: "Wo? — статика → Dativ. Im, in der и т.д." },
  { id: "q0086", topic: "grammar:verbs", level: "A1", difficulty: 1, type: "mc", q: "«Ich bin ___» — что лучше подставить?", opts: ["Hunger", "müde", "Auto", "Buch"], ans: 1, explain: "sein + прил. → müde. haben + сущ. → Hunger." },
  { id: "q0087", topic: "grammar:verbs", level: "A1", difficulty: 1, type: "mc", q: "Partizip II от «besuchen»?", opts: ["gebesucht", "besucht", "besuchte", "besuchen"], ans: 1, explain: "Глаголы с be-/er-/ver- → БЕЗ ge-." },
  { id: "q0088", topic: "grammar:verbs", level: "A1", difficulty: 1, type: "mc", q: "Partizip II от «organisieren»?", opts: ["georganisiert", "organisiert", "organisierte", "organisieren"], ans: 1, explain: "Глаголы на -ieren → БЕЗ ge-." },
  { id: "q0089", topic: "grammar:verbs", level: "A1", difficulty: 1, type: "mc", q: "Partizip II от «machen»?", opts: ["machte", "gemacht", "macht", "gemächt"], ans: 1, explain: "Регулярный: ge- + основа + -t." },
  { id: "q0090", topic: "grammar:modal", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Здесь нельзя курить.»", words: ["Man", "darf", "hier", "nicht", "rauchen."], explain: "Modalverb на 2-й, Infinitiv в конец. nicht — отрицание действия." },
  { id: "q0091", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Я встаю в 7.»", words: ["Ich", "stehe", "um", "7", "Uhr", "auf."], explain: "aufstehen — отделяемая. auf уходит в конец." },
  { id: "q0092", topic: "grammar:verbs", level: "A2", difficulty: 4, type: "fill", q: "Präteritum от «haben» для «ich»?", ans: "hatte", hint: "имел", explain: "ich hatte." },
  { id: "q0093", topic: "grammar:cases", level: "A1", difficulty: 4, type: "fill", q: "Артикль в Akk от «der Hund»?", ans: "den", hint: "m → меняется", explain: "der → den (только m меняется в Akk)." },
  { id: "q0094", topic: "grammar:cases", level: "A1", difficulty: 4, type: "fill", q: "Артикль в Dat от «die Frau»?", ans: "der", hint: "f, Dat", explain: "f, Dat → der. Совпадает по форме с Nom m, но это Dat f." },
  { id: "q0095", topic: "communication:greetings", level: "A1", difficulty: 1, type: "mc", q: "«Wie geht es Ihnen?» — как ответить хорошо?", opts: ["Sehr gut, danke", "Auf Wiedersehen", "Gesundheit", "Wie bitte?"], ans: 0, explain: "Sehr gut, danke. Und Ihnen?" },
  { id: "q0096", topic: "communication:greetings", level: "A1", difficulty: 1, type: "mc", q: "Что значит «Tut mir leid»?", opts: ["Удачи!", "Мне жаль", "Очень приятно", "Что-нибудь ещё?"], ans: 1, explain: "Tut mir leid — мне жаль / прости." },
  { id: "q0097", topic: "communication:greetings", level: "A1", difficulty: 1, type: "mc", q: "Как сказать «Я голоден»?", opts: ["Ich bin Hunger", "Ich habe Hunger", "Mir ist Hunger", "Ich Hunger habe"], ans: 1, explain: "haben + Hunger (не sein!)." },
  { id: "q0098", topic: "communication:general", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Я бы хотел кофе.»", words: ["Ich", "hätte", "gern", "einen", "Kaffee."], explain: "hätte gern — вежливый заказ. der Kaffee (m) → einen." },
  { id: "q0099", topic: "communication:general", level: "A2", difficulty: 4, type: "tiles", q: "Составь: «Счёт, пожалуйста.»", words: ["Die", "Rechnung,", "bitte."], explain: "Die Rechnung, bitte. = Zahlen bitte." },
];

