const RULES = [
  { id: "r0001", title: "Personalpronomen - три падежа", topic: "grammar:pronouns", domen: "grammar", group: "pronouns", level: "A1", content_md: "### Personalpronomen - три падежа\n**Nominativ (Wer?)** | **Akkusativ (Wen?)** | **Dativ (Wem?)** |\nich | mich | mir |\ndu | dich | dir |\ner | ihn | ihm |\nes | es | ihm |\nsie (она) | sie | ihr |\nwir | uns | uns |\nihr (вы, группа) | euch | euch |\nsie (они) | sie | ihnen |\nSie (вежл.) | Sie | Ihnen |\n⚠ es в Dativ — **ihm**, не ihr | **ihr** = «ей» (Dativ от sie-она) и «вы» (группа, Nominativ) — два разных значения!", topics: ["grammar:pronouns"] },
  { id: "r0002", title: "Reflexivpronomen - возвратные местоимения (себя / себе)", topic: "grammar:pronouns", domen: "grammar", group: "pronouns", level: "A1", content_md: "### Reflexivpronomen - возвратные местоимения (себя / себе)\n**Лицо** | **Akkusativ** | **Dativ** |\nich | mich | mir |\ndu | dich | dir |\ner/sie/es | sich | sich |\nwir | uns | uns |\nihr | euch | euch |\nsie/Sie | sich | sich |\n💡 ich/du/wir/ihr — совпадают с Personalpronomen | **er/sie/es** и **sie/Sie** → всегда **sich**\nAkk vs Dat: **Ich wasche mich** (я моюсь — себя, Akk) | **Ich wasche mir die Hände** (я мою себе руки — кому? мне, Dat)", topics: ["grammar:pronouns"] },
  { id: "r0003", title: "Запрет через man - нельзя", topic: "grammar:wordorder", domen: "grammar", group: "wordorder", level: "A1", content_md: "Конструкция запрета через **man** (= \"нельзя\" / \"не разрешается\"):\n**Структура** | **Пример** | **Перевод** |\nMan darf nicht + Verb | Man darf nicht grillen. | Здесь нельзя жарить на гриле. |\nMan darf kein + Nomen | Man darf keine Haustiere haben. | Нельзя держать домашних животных. |\n💡 **nicht** — отрицает действие | **kein/keine** — отрицает существительное💡 **man** — безличное местоимение (= \"нельзя / не разрешается\" — без конкретного лица)", topics: ["grammar:wordorder"] },
  { id: "r0004", title: "Perfekt: sein или haben?", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A1", content_md: "**Глагол** | **Используется с** | **Пример** |\n**sein** | прилагательные, профессии, национальности | Ich **bin** Arzt. / Er **ist** müde. |\n**haben** | существительные (что-то у тебя есть) | Ich **habe** Hunger. / Er **hat** Zeit. |\n💡 Проверка: «я **являюсь**...?» → sein  |  «у меня **есть**...?» → haben", topics: ["grammar:verbs"] },
  { id: "r0005", title: "Präteritum: sein", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A1", content_md: "sein — быть\nich | war |\ndu | warst |\ner/sie/es | war |\nwir | waren |\nihr | wart |\nsie/Sie | waren |\nhaben — иметь\nich | hatte |\ndu | hattest |\ner/sie/es | hatte |\nwir | hatten |\nihr | hattet |\nsie/Sie | hatten |\n💡 Wie war das Treffen? — Das Treffen **war** toll! / Wir **hatten** viel Spaß!", topics: ["grammar:verbs"] },
  { id: "r0006", title: "wissen vs kennen", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A1", content_md: "**Глагол** | **Когда используется** | **Пример** |\n**wissen** | знать факт / информацию | Ich weiß, wo er wohnt. |\n**kennen** | знать человека / быть знакомым | Ich kenne ihn gut. |\nСпряжение wissen (неправильный!):\nich | weiß |\ner/sie/es | weiß |\nihr | wisst |\ndu | weißt |\nwir | wissen |\nsie/Sie | wissen |", topics: ["grammar:verbs"] },
  { id: "r0007", title: "Возвратное местоимение sich", topic: "grammar:pronouns", domen: "grammar", group: "pronouns", level: "A1", content_md: "**sich** = себя / себе. Используется в возвратных глаголах, когда действие направлено на самого субъекта.\n**Лицо** | **Возвратное** | **Пример (sich vorstellen)** |\nich | mich | Ich stelle **mich** vor |\ndu | dich | Du stellst **dich** vor |\ner / sie / es | **sich** | Er stellt **sich** vor |\nwir | uns | Wir stellen **uns** vor |\nihr | euch | Ihr stellt **euch** vor |\nsie / Sie | **sich** | Sie stellen **sich** vor |", topics: ["grammar:pronouns"] },
  { id: "r0008", title: "Порядок слов с Modalverb", topic: "grammar:wordorder", domen: "grammar", group: "wordorder", level: "A1", content_md: "В предложениях с **модальным глаголом (Modalverb)** и **смысловым глаголом (Infinitiv)** используется особый порядок слов:\n**Элемент** |\n**Позиция в предложении** |\n**Пример** |\nModalverb (спрягаемый глагол) |\n2-я позиция |\nIch **kann** ... |\nInfinitiv (основной глагол) |\nВ конце предложения |\n... den Raum **vorbereiten**. |\n👉 **Разделяемые глаголы (trennbare Verben)** в предложениях с Modalverb + Infinitiv **не разделяются** и остаются в конце предложения целиком.\n**Пример:** Ich kann am Freitag den Raum **vorbereiten**.", topics: ["grammar:wordorder"] },
  { id: "r0009", title: "Окончания Präsens", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A1", content_md: "**Лицо** | **Окончание** | **Пример (machen)** |\nich | +e | ich mache |\ndu | +st | du machst |\ner / sie / es | +t | er macht |\nwir | +en | wir machen |\nihr | +t | ihr macht |\nsie (Pl) / Sie | +en | sie machen |", topics: ["grammar:verbs"] },
  { id: "r0010", title: "Nominativ - Wer? Was? (кто? что?)", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "### Nominativ - Wer? Was? (кто? что?)\nПодлежащее. Кто/что совершает действие.\n**** | **m** | **f** | **n** | **Pl** |\nопр. | der | die | das | die |\nнеопр. | ein | eine | ein | - |", topics: ["grammar:cases"] },
  { id: "r0011", title: "Akkusativ - Wen? Was? (кого? что?)", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "### Akkusativ - Wen? Was? (кого? что?)\nПрямое дополнение. Меняется только m: der→den, ein→einen.\n**** | **m** | **f** | **n** | **Pl** |\nопр. | den | die | das | die |\nнеопр. | einen | eine | ein | - |", topics: ["grammar:cases"] },
  { id: "r0012", title: "Dativ - Wem? (кому?)", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "### Dativ - Wem? (кому?)\nИспользуется с предлогами mit, bei, beim и др.\n**** | **m** | **f** | **n** | **Pl** |\nопр. | dem | der | dem | den |\nнеопр. | einem | einer | einem | - |", topics: ["grammar:cases"] },
  { id: "r0013", title: "Определённый и неопределённый артикль", topic: "grammar:articles", domen: "grammar", group: "articles", level: "A1", content_md: "Артикль показывает, насколько объект определён.\n**der / das / die** — объект известный, конкретный (тот самый).\n**ein / eine** — объект называется впервые, один из многих, без конкретики.\n**kein / keine** — отрицание: объекта / признака нет.\n**без артикля** — множ. число без уточнения, вещество или обобщённо (неопределённый предмет).\n**Пример** | **Перевод** |\nMögen Sie Fisch? | Вам нравится рыба? (вообще) |\nMögen Sie den Fisch? | Вам нравится эта рыба? (конкретная) |\nIch habe kein Auto. | У меня нет машины. |\nIch trinke Wasser. | Я пью воду. (вещество, без артикля) |", new: true, topics: ["grammar:articles", "new:new-rules"] },
  { id: "r0014", title: "sein и ihr — притяжательные", topic: "grammar:pronouns", domen: "grammar", group: "pronouns", level: "A1", content_md: "sein = его (er), ihr = её (sie). Окончания как у mein/meine.\n**Существительное** | **ich** | **er (sein)** | **sie (ihr)** |\nder Beruf (m) | mein Beruf | sein Beruf | ihr Beruf |\ndas Alter (n) | mein Alter | sein Alter | ihr Alter |\ndie Augenfarbe (f) | meine Augenfarbe | seine Augenfarbe | ihre Augenfarbe |\ndie Hobbys (Pl) | meine Hobbys | seine Hobbys | ihre Hobbys |\n⚡ m/n → mein/sein/ihr  |  f/Pl → meine/seine/ihre", topics: ["grammar:pronouns"] },
  { id: "r0015", title: "Partizip II: правило приставки ge-", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A1", content_md: "### Partizip II: правило приставки ge-\n**Инфинитив** | **Partizip II** | **Перевод** |\nöffnen | geöffnet | открытый |\nschließen | geschlossen | закрытый |\nmachen | gemacht | сделанный |\n⚠ **ge- НЕ добавляется в двух случаях:**\n1. Глаголы с неотделяемой приставкой (be-, er-, ver-, ent-, zer-): **besuchen → besucht**, verstehen → verstanden\n2. Глаголы на **-ieren**: organisieren → **organisiert**, fotografieren → fotografiert", topics: ["grammar:verbs"] },
  { id: "r0016", title: "Конструкция gern + глагол", topic: "grammar:wordorder", domen: "grammar", group: "wordorder", level: "A1", content_md: "Глагол меняется по лицу, gern остаётся неизменным\n**Пример** | **Перевод** |\nEr kocht gern | Он любит готовить |\nSie malt gern | Она любит рисовать |\nIch singe gern | Я люблю петь |", topics: ["grammar:wordorder"] },
  { id: "r0017", title: "wohin vs wo", topic: "grammar:wfragen", domen: "grammar", group: "wfragen", level: "A1", content_md: "**Wohin?** (куда?) — вопрос о направлении движения. Используется **in + Akkusativ**.\n**Артикль** | **+ in** | **Пример** |\nder (m) | in **den** | Ich gehe **in den Park** — иду в парк |\ndas (n) | in **das** = **ins** | Ich gehe **ins Kino** — иду в кино |\ndie (f) | in **die** | Ich gehe **in die Kneipe** — иду в паб |\n💡 **in + das = ins** (слитная форма) | **in + dem = im** (для Wo? — где?)\n⚠ Различай: **Wohin?** → Akkusativ (in den, ins, in die) | **Wo?** → Dativ (im, im, in der)", topics: ["grammar:wfragen"] },
  { id: "r0018", title: "sollen vs müssen", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A1", content_md: "**** | **sollen** | **müssen** |\nИсточник | внешний — кто-то сказал / так положено | внутренний / объективный — сам так решил или иначе нельзя |\nПример | Du **sollst** nicht rauchen(тебе говорят, что нельзя) | Ich **muss** schlafen(сам устал, надо) |\nЕщё | Ich **soll** Milch kaufen(мама попросила) | Ich **muss** Milch kaufen(дома кончилось) |\n💡 Грубо: **sollen** — «надо для кого-то» | **müssen** — «надо мне / по сути»", topics: ["grammar:verbs"] },
  { id: "r0019", title: "Прилагательное в словарной форме", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A1", content_md: "Прилагательное в словаре стоит **без окончания** (groß, schön, nächst, gut). Но **перед существительным** оно ВСЕГДА получает окончание — зависит от рода, числа и падежа.\n📍 Две позиции прилагательного:\n**Позиция** | **Окончание** | **Пример** |\nПосле sein / werden / bleiben | ❌ нет окончания | Das Haus ist **groß** | Er bleibt **gesund** |\nПеред существительным | ✅ есть окончание | ein **großes** Haus | der **gesunde** Mann |\n📍 Окончания после **определённого артикля** (der/die/das):\n**Падеж** | **m (der)** | **f (die)** | **n (das)** | **Pl (die)** |\nNom | -e | -e | -e | -en |\nAkk | **-en** | -e | -e | -en |\nDat | -en | -en | -en | -en |\n📍 Примеры с **nächst** (следующий):\n**Падеж / Род** | **Форма** | **Перевод** |\nf, Nom/Akk | nächst**e** Woche | следующая неделя / на следующей неделе |\nm, Akk | nächst**en** Montag | в следующий понедельник |\nn, Nom/Akk | nächst**es** Jahr | следующий год |\nDat (любой род) | im nächst**en** Jahr | в следующем году |\n💡 Простое правило: **в Dativ всегда -en** | в Akk у m-рода тоже **-en** | остальное обычно **-e**\n⚠ Без артикля (неопределённый/нулевой) — окончания немного другие. Это уровень A2+, пока запомни базовый случай.", topics: ["grammar:adjectives"] },
  { id: "r0020", title: "Отделяемые приставки", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A1", content_md: "Отделяемые приставки\n**Приставка** | **Значение** |\nauf- | вверх / открыто |\nan- | на / у |\nein- | в / внутрь |\naus- | снаружи / выключено |\nmit- | с (вместе) |\nvor- | перед / от |\nab- | от / закрыто |\nzu- | к / навстречу |\nfern- | вдали / удалённый |\nweg- | прочь |\nzurück- | назад / обратно |", topics: ["grammar:verbs"] },
  { id: "r0021", title: "Суффикс -lich — образование прилагательных", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A1", content_md: "### Суффикс **-lich** — образование прилагательных\nСуффикс **-lich** превращает существительное в прилагательное со значением «относящийся к / похожий на». Похож на русский суффикс «-ный».\n**Существительное** | **+ -lich** | **Перевод** |\ndas Herz (сердце) | herz**lich** | сердечный |\nder Tag (день) | täg**lich** | ежедневный |\nder Freund (друг) | freund**lich** | дружелюбный |\nder Mensch (человек) | mensch**lich** | человеческий |\nder Monat (месяц) | monat**lich** | ежемесячный |\nder Beruf (профессия) | beruf**lich** | профессиональный |\n💡 Часто корневая гласная меняется на умлаут: Tag → t**ä**glich, Nacht → n**ä**chtlich", topics: ["grammar:adjectives"] },
  { id: "r0022", title: "Perfekt — прошедшее разговорное время (haben/sein + Partizip II)", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A2", content_md: "### Perfekt — прошедшее разговорное время\nСтруктура: **haben/sein + Partizip II** (в конце предложения)\n\n**Глагол** | **Вспомогательный** | **Пример** |\nhaben | большинство глаголов | Ich **habe** gearbeitet. |\nsein | движение, смена позиции/ситуации | Ich **bin** gegangen. |\n\n### Когда sein?\n**Категория** | **Примеры глаголов** |\nСмена позиции (движение из А в Б) | fahren, gehen, fliegen, laufen, kommen, aufstehen, ankommen, abfahren, einsteigen, aussteigen, umsteigen, einziehen, umziehen, weggehen, zurückkommen |\nСмена состояния/ситуации | aufwachsen, wachsen, einschlafen, explodieren, passieren, sterben, werden |\nИсключения (sein/bleiben) | sein → Ich bin in NY gewesen. | bleiben → Ich bin geblieben. |\n\n### Всё остальное — haben\nIch habe gearbeitet. | Ich habe gegessen. | Ich habe geschlafen.\n\n### Partizip II — как образуется?\n**Тип глагола** | **Схема** | **Пример** |\nПравильный (regel) | ge- + Stamm + -t | arbeiten → ge**arbeit**et |\nНеправильный (unregel) | ge- + Stamm + -en (с чередованием) | schlafen → ge**schlaf**en |\nОтдел. приставка | Приставка + ge- + Stamm | aufstehen → auf**ge**standen |\nНеотдел. / -ieren | без ge- | besuchen → besucht, passieren → passiert |", topics: ["grammar:verbs"] },
  { id: "r0023", title: "Nebensatz mit weil", topic: "grammar:wordorder", domen: "grammar", group: "wordorder", level: "A1", content_md: "### Nebensatz mit weil — придаточное причины\n\n**weil** (потому что) — подчинительный союз.\nГлагол уходит в **конец** придаточного предложения.\n\n### Структура\n**Hauptsatz** | **Nebensatz** |\nIch bleibe zu Hause, | weil ich krank **bin**. |\nIch lerne Deutsch, | weil es interessant **ist**. |\nEr kommt nicht, | weil er arbeiten **muss**. |\n\n### Примеры с модальным глаголом\n**Hauptsatz** | **Nebensatz** |\nIch gehe nicht aus, | weil ich lernen **muss**. |\nSie bleibt zu Hause, | weil sie schlafen **will**. |\n\n⚠ Перед weil всегда ставится **запятая**\n⚠ Глагол — всегда **последний** в Nebensatz\n💡 Вопрос к Nebensatz: **Warum? / Weshalb?** (почему?)", examples: "Ich lerne Deutsch, weil es interessant ist.", topics: ["grammar:wordorder"] },
  { id: "r0024", title: "Падежи: роль в предложении", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "### Падежи: роль в предложении\n\n**Падеж** | **Роль** | **Вопрос** | **Пример**\nNominativ | только субъект — кто совершает действие | Wer? | **Ich** lerne Deutsch.\nAkkusativ | субъект + прямой объект — кого/что затрагивает действие | Wen? Was? | Ich kaufe **einen Kaffee**.\nDativ | субъект + косвенный объект — кому, для кого, где | Wem? | Ich gebe **dir** das Buch.\n\n💡 **Nominativ** — всегда только один в предложении, это «деятель»\n💡 **Akkusativ** — прямой объект, отвечает на «что/кого?»\n💡 **Dativ** — косвенный объект, отвечает на «кому?», также используется после предлогов mit, bei, in (Wo?)", examples: "Ich bin müde. (Nom) | Ich kaufe einen Apfel. (Akk) | Ich gebe dir das Buch. (Dat)", note: "Nominativ — всегда субъект, никогда не меняется после артикля. Akkusativ — меняется только m: der→den, ein→einen. Dativ — меняется всё: dem/der/dem, einem/einer/einem. Предлоги mit, bei, nach, von, zu, aus — всегда Dativ. Предлоги durch, für, gegen, ohne, um — всегда Akkusativ.", topics: ["grammar:cases"] },
  { id: "r0025", title: "Verben mit Dativ", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A2", content_md: "### Verben mit Dativ — глаголы, после которых всегда Dativ\n\nПосле некоторых глаголов объект стоит **всегда в Dativ** (не Akkusativ!).\n\n**Глагол** | **Пример** | **Перевод**\nantworten | Ich antworte **dir**. | Я отвечаю тебе.\ndanken | Ich danke **dem Team**. | Я благодарю команду.\ngefallen | Das gefällt **mir**. | Мне это нравится.\ngehören | Das gehört **mir**. | Это принадлежит мне.\ngratulieren | Ich gratuliere **dir**. | Я поздравляю тебя.\nhelfen | Er hilft **der Kundin**. | Он помогает клиентке.\nschmecken | Das schmeckt **mir**. | Мне это вкусно.", examples: "Ich danke dir / Ihnen / euch. | Ich danke dem Team / den Kollegen. | Meine Tochter hilft mir immer. | Der Verkäufer hilft der Kundin.", note: "Запомни список: antworten, danken, gefallen, gehören, gratulieren, helfen, schmecken — после них всегда Dativ. Проверка: задай вопрос «кому?» (Wem?).", topics: ["grammar:cases"] },
  { id: "r0026", title: "Порядок Dativ и Akkusativ в предложении", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A2", content_md: "### Порядок Dativ и Akkusativ в предложении\n\n**Правило 1: два существительных** → Dativ перед Akkusativ\n**Субъект** | **Глагол** | **Dativ** | **Akkusativ**\nIch | gebe | dem Mann | das Buch.\nEr | zeigt | der Kundin | den Weg.\n\n**Правило 2: местоимение + существительное** → местоимение первым\n**Субъект** | **Глагол** | **Pronomen** | **Nomen**\nIch | gebe | ihm | das Buch.\nEr | zeigt | ihr | den Weg.\n\n**Правило 3: оба местоимения** → Akkusativ перед Dativ\n**Субъект** | **Глагол** | **Akkusativ** | **Dativ**\nIch | gebe | es | ihm.\nEr | zeigt | es | ihr.\n\n💡 Запомни: **два существительных → Dat→Akk** | **оба местоимения → Akk→Dat**", examples: "Ich gebe dem Mann das Buch. | Ich gebe ihm das Buch. | Ich gebe es ihm.", note: "Проверка: если оба слова — существительные, Dativ всегда первый. Если оба местоимения — Akkusativ первый. Местоимение всегда «тянется» вперёд.", topics: ["grammar:cases"] },
  { id: "r0027", title: "Verben mit Dativ und Akkusativ", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A2", content_md: "### Verben mit Dativ und Akkusativ — глаголы с двумя дополнениями\n\nПосле некоторых глаголов стоят сразу ДВА объекта: кому (Dativ) + что (Akkusativ).\n\n**Роль** | **Падеж** | **Вопрос** | **Артикли (m / f / n / Pl)**\nPerson 1 | Nominativ | Wer? | der · die · das · die / ein · eine · ein · —\nPerson 2 | Dativ | Wem? | dem · der · dem · den / einem · einer · einem · —\nObjekt | Akkusativ | Was? | den · die · das · die / einen · eine · ein · —\n\n💡 Порядок: Субъект → Глагол → **Dativ** → **Akkusativ** (кому → что)\n💡 У неопр. артикля во множественном числе формы нет (просто без артикля)", examples: "**Пример** | **Перевод**||\nIch gebe dem Mann das Buch. | Я даю мужчине книгу.||\nEr schenkt der Frau einen Ring. | Он дарит женщине кольцо.||\nWir zeigen den Kindern die Stadt. | Мы показываем детям город.||", note: "Типичные глаголы: geben, schenken, zeigen, bringen, schicken, kaufen, erklären, empfehlen, leihen, schreiben, wünschen, anbieten. Проверка: задай два вопроса — «кому?» (Wem? → Dativ) и «что?» (Was? → Akkusativ). Порядок при двух существительных: Dativ перед Akkusativ.", topics: ["grammar:cases"] },
  { id: "r0028", title: "Artikelformen: Nom / Dativ / Akkusativ", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "### Artikelformen: Nominativ / Dativ / Akkusativ\n\n**bestimmter Artikel (der/die/das)**\n\n| | Nom | Dativ | Akkusativ |\n\n| m | der | dem | den |\n| f | die | der | die |\n| n | das | dem | das |\n| Pl | die | den | die |\n\n**unbestimmter Artikel (ein/eine)**\n\n| | Nom | Dativ | Akkusativ |\n\n| m | ein | einem | einen |\n| f | eine | einer | eine |\n| n | ein | einem | ein |\n| Pl | — | — | — |\n\n💡 Меняется только **m** в Akkusativ: der→den, ein→einen\n💡 Dativ **Pl** всегда: den + существительное + **-n** (den Kindern, den Männern)\n💡 unbestimmter Artikel во Pl — отсутствует", examples: "Ich sehe den Mann. (m, Akk) | Ich helfe der Frau. (f, Dat) | Das gehört dem Kind. (n, Dat) | Ich gebe den Kindern das Buch. (Pl, Dat)", note: "Nominativ — субъект (Wer?). Akkusativ — прямой объект (Wen? Was?). Dativ — косвенный объект (Wem?). Изменения: m Akk: der→den, ein→einen. Dativ Pl: +n к существительному.", topics: ["grammar:cases"] },
  { id: "r0029", title: "Nebensatz — порядок глаголов", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A2", content_md: "### Nebensatz — порядок глаголов\n\n**Спрягаемый глагол** всегда уходит в **конец** Nebensatz.  \nЕсли глаголов два — второй (Infinitiv или Partizip II) стоит перед ним.\n\n\n\n### Структура\n\n| Hauptsatz | Nebensatz |\n| Sie geht zum Vermieter, | weil sie den Schlüssel abgeben **muss**. |\n| Sie ist müde, | weil sie viel gearbeitet **hat**. |\n| Er kommt nicht, | weil er krank **ist**. |\n| Ich glaube, | dass er krank **ist**. |\n\n\n### Модальный + смысловой глагол\n\n| Hauptsatz | Nebensatz |\n| Ich gehe nicht aus, | weil ich lernen **muss**. |\n| Sie bleibt zu Hause, | weil sie schlafen **will**. |\n| Wir bleiben hier, | weil wir früh aufstehen **müssen**. |\n\n\n\n### Perfekt\n\n| Hauptsatz | Nebensatz |\n| Er ist müde, | weil er viel gearbeitet **hat**. |\n| Sie weiß es, | weil er nach Berlin gefahren **ist**. |\n\n\n\n### Сравни\n\n|_| Hauptsatz | Nebensatz |\n| Без модального | *Sie gibt den Schlüssel ab.* | *weil sie den Schlüssel abgibt.* |\n| С модальным | *Sie muss den Schlüssel abgeben.* | *weil sie den Schlüssel abgeben **muss**.* |\n\n\n\n⚠ Перед придаточным всегда ставится **запятая**  \n⚠ Спрягаемый глагол — всегда **последний** в Nebensatz  \n💡 **Запоминалка:** спрягаемый глагол — «король» Nebensatz. Всё остальное — перед ним.", examples: "weil ich lernen muss | weil sie gearbeitet hat | weil er krank ist | weil ich lernen muss | weil sie gearbeitet hat | weil er krank ist | dass er kommt", note: "Подсказка как определить спрягаемый: это тот глагол, который меняется по лицам (ich/du/er). В словаре он стоит как infinitiv (müssen, haben), а в предложении принимает форму (muss, hat).\nЭто правило универсальное — работает для всех Nebensatz (weil, dass, wenn, obwohl, damit, ob, als, während, bevor, nachdem)\n💡 Если в предложении два глагола (модальный, Perfekt...) — см. правило о порядке глаголов в Nebensatz.\n💡 dass — тоже Nebensatz, глагол в конец работает так же: Ich weiß, dass er kommt.", topics: ["grammar:cases"] },
  { id: "r0030", title: "Сокращения артиклей: am / im", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "### Сокращения артиклей: am / im\n\nВ разговорной и письменной речи предлог + артикль **dem** сливаются:\n\n| Предлог | + dem | = |\n|---------|-------|---|\n| an | an + dem | **am** |\n| in | in + dem | **im** |\n\n💡 **am** и **im** — это всегда Dativ (Wo?)\n💡 Ich bin **im** Büro. = Ich bin in dem Büro.\n💡 Ich bin **am** Bahnhof. = Ich bin an dem Bahnhof.\n\n⚠ Только с **dem** (m/n, Dativ) — с **der** (f) сокращения нет: in der Küche (не im)", examples: "Ich bin im Büro. | Er steht am Fenster. | Das Buch liegt im Regal.", note: "am = an + dem | im = in + dem | только Dativ (Wo?) | женский род — без сокращения: in der Küche, an der Wand", topics: ["grammar:cases"] },
  { id: "r0031", title: "Wo? Präposition + Dativ", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "### Wo? Präposition + Dativ\n\nНа вопрос **Wo?** (где?) предлоги места требуют **Dativ**.\n\n| Предлог | Значение | Пример |\n|---------|----------|--------|\n| auf | на (горизонт.) | Das Buch liegt **auf dem Tisch**. |\n| unter | под | Die Katze sitzt **unter dem Stuhl**. |\n| in | в | Das Heft ist **in der Tasche**. |\n| an | у / на (верт.) | Das Bild hängt **an der Wand**. |\n| über | над | Die Lampe hängt **über dem Tisch**. |\n| vor | перед | Das Fahrrad steht **vor der Tür**. |\n| hinter | за | Der Schrank steht **hinter der Tür**. |\n| neben | рядом с | Die Pflanze steht **neben dem Fenster**. |\n| zwischen | между | Der Tisch steht **zwischen den Pflanzen**. |\n\n💡 Wo? → всегда **Dativ**\n💡 Wohin? → всегда **Akkusativ** (куда кладём/ставим)", examples: "Auf dem Tisch. | Unter dem Buch. | In der Tasche. | Zwischen den Pflanzen. | An der Wand.", note: "Wo? = где стоит/лежит/висит → Dativ | Wohin? = куда ставим/кладём → Akkusativ | an/in + dem = am/im", topics: ["grammar:cases"] },
  { id: "r0032", title: "Modalverben im Präteritum", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A2", content_md: "**Лицо** | **Endung** | **müssen** | **können** | **wollen** | **dürfen** |\nich | — | musste | konnte | wollte | durfte |\ndu | -st | musstest | konntest | wolltest | durftest |\ner/sie/es | — | musste | konnte | wollte | durfte |\nwir | -en | mussten | konnten | wollten | durften |\nihr | -t | musstet | konntet | wolltet | durftet |\nsie/Sie | -en | mussten | konnten | wollten | durften |\n💡 Основа + -te + окончания (ich/er — без окончания). Умлаут исчезает: müssen→musste, können→konnte, dürfen→durfte. Genauso: sollen→sollte, mögen→mochte.", note: "прошедшее модальных в речи чаще через Präteritum, а не Perfekt", topics: ["grammar:verbs"] },
  { id: "r0033", title: "Adjektivdeklination (ein-/Possessiv, Nom + Akk + Dativ)", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A2", content_md: "**Nominativ** (Hier ist/sind …) | артикль + оконч. | пример\nm — der Anzug | ein / mein neuer | ein neuer Anzug\nn — das Hemd | ein / mein neues | ein neues Hemd\nf — die Hose | eine / meine neue | eine neue Hose\nPl — die Stiefel | meine neuen | meine neuen Stiefel\n**Akkusativ** (Ich brauche/suche …) | артикль + оконч. | пример\nm — der Anzug | einen / meinen neuen | einen neuen Anzug\nn — das Hemd | ein / mein neues | ein neues Hemd\nf — die Hose | eine / meine neue | eine neue Hose\nPl — die Stiefel | meine neuen | meine neuen Stiefel\n**Dativ** (Das passt zu …) | артикль + оконч. | пример\nm — der Anzug | einem / meinem neuen | einem neuen Anzug\nn — das Hemd | einem / meinem neuen | einem neuen Hemd\nf — die Hose | einer / meiner neuen | einer neuen Hose\nPl — die Stiefel | meinen neuen | meinen neuen Stiefeln\n💡 Nom→Akk меняется только в m-роде: neuer → neuen. В Dativ окончание прилагательного ВСЕГДА -en (все рода). После kein — как после mein. В Pl Dativ ещё и существительное получает -n: meinen neuen Stiefeln. lila / rosa — без окончаний.", note: "Plural всегда -en (с ein-словом/Possessiv/kein)\nDativ всегда -en; в Pl Dativ существительное тоже +n. Plural всегда -en.", new: true, topics: ["grammar:adjectives", "new:new-rules"] },
  { id: "r0034", title: "Zeitpräpositionen: am / im / um", topic: "grammar:cases", domen: "grammar", group: "cases", level: "A1", content_md: "**am** (+ Dativ) | дни, части суток, дата | am Montag, am Wochenende, am Morgen, am 3. Mai\n**im** (+ Dativ) | месяцы, времена года | im Januar, im Sommer, im Frühling / Herbst / Winter\n**um** (+ Akkusativ) | точное время | um 8 Uhr, um Mitternacht, um halb neun\n💡 Исключение: in der Nacht (не «am»). Вопросы: Um wie viel Uhr? / An welchem Tag? / In welchem Monat?", note: "Исключение: in der Nacht", topics: ["grammar:cases"] },
  { id: "r0035", title: "Modalverben: Bedeutung (will / muss / darf / kann / möchte)", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A2", content_md: "Ich **will** arbeiten. | wollen — хочу (твёрдое намерение)\nIch **muss** arbeiten. | müssen — должен / надо\nIch **darf** arbeiten. | dürfen — можно / разрешено\nIch **kann** arbeiten. | können — могу / умею\nIch **möchte** arbeiten. | хотел бы (вежливо, форма от mögen)\n💡 möglich — это НЕ глагол, а прилагательное «возможный»: Das ist möglich. После модального инфинитив уходит в конец: Ich kann heute nicht arbeiten.", note: "möchte — вежливая форма от mögen", topics: ["grammar:verbs"] },
  { id: "r0036", title: "Zahl + **-jährig** = «X-летний» (прилагательное)\nacht + jährig → achtjährig — восьмилетний\nBeispiele: ein dreijähriges Kind, eine 18-jährige Frau\n💡 Пишется слитно; число словом или цифрой с дефисом (8-jährig). Так же: -tägig (дни), -stündig (часы), -monatig (месяцы).", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A2", content_md: "Zahl + **-jährig** = «X-летний» (прилагательное)\nacht + jährig → achtjährig — восьмилетний\nBeispiele: ein dreijähriges Kind, eine 18-jährige Frau\n💡 Пишется слитно; число словом или цифрой с дефисом (8-jährig). Так же: -tägig (дни), -stündig (часы), -monatig (месяцы).", note: "≠ jährlich (ежегодно)", topics: ["grammar:verbs"] },
  { id: "r0037", title: "Ordinalzahlen (порядковые числительные)", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A2", content_md: "Образование: число + **-te** (2–19) / **-ste** (от 20)\n1. erste · 2. zweite · 3. dritte · 4. vierte · 7. siebte · 8. achte\n20. zwanzigste · 21. einundzwanzigste · 100. hundertste\n💡 Исключения: erste (не einte), dritte (не dreite), siebte, achte (один t). Склоняются как прилагательные: der erste Stock → im ersten Stock, am dritten Mai.", note: "склоняются как прилагательные после артикля", topics: ["grammar:adjectives"] },
  { id: "r0040", title: "Adjektivdeklination ohne Artikel (starke Endungen)", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A2", content_md: "Без артикля прилагательное само несёт сигнал рода и падежа — берёт окончание артикля. Пример: **nett**.\n**Падеж** | **m** | **n** | **f** | **Pl** |\nNom | netter Mann | nettes Kind | nette Frau | nette Leute |\nAkk | netten Mann | nettes Kind | nette Frau | nette Leute |\nDat | nettem Mann | nettem Kind | netter Frau | netten Leuten |\n💡 Окончания почти как у der/das/die: m Nom -er, n -es, в Dativ m/n -em. Бывает после чисел, viele / wenige и с вещественными словами: kaltes Wasser, guter Wein, frische Luft.", note: "Сильное склонение: нет артикля → прилагательное берёт окончание артикля.", new: true, topics: ["grammar:adjectives", "new:new-rules"] },
  { id: "r0041", title: "Komparativ (сравнительная степень)", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A2", content_md: "**Komparativ** = «более / -ее». Образование: прилагательное + **-er**. Сравнение — через **als** (чем).\n**Позитив** | **Komparativ** | **Пример** |\nschnell | schneller | Er läuft schneller als ich. |\nklein | kleiner | Mein Zimmer ist kleiner als deins. |\nschön | schöner | Heute ist es schöner als gestern. |\n💡 Короткие с a / o / u часто получают **умлаут**: alt → älter, groß → größer, jung → jünger, kurz → kürzer, lang → länger, warm → wärmer.\n⚠ Неправильные (запомнить): gut → besser | viel → mehr | gern → lieber | hoch → höher | teuer → teurer | nah → näher", note: "Сравнение через als. Умлаут у коротких a/o/u. Особые: besser, mehr, lieber, höher, teurer.", new: true, topics: ["grammar:adjectives", "new:new-rules"] },
  { id: "r0042", title: "Superlativ (превосходная степень)", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A2", content_md: "**Superlativ** = «самый». Форма зависит от позиции:\n**Позиция** | **Форма** | **Пример** |\nС глаголом / предикативно | am …**sten** | Er läuft am schnellsten. |\nПеред существительным (с артиклем) | der/die/das …**ste(n)** | Das ist der schnellste Mann. |\n💡 С артиклем — БЕЗ am: die schnellsten Sportler (не «die am schnellsten»). С **am** окончание всегда **-sten**.\n💡 Умлаут — если он есть в Komparativ: kurz → kürzer → am kürzesten.\n💡 После **-t, -d, -s, -sch, -x, -z** вставляется e → окончание **-este(n)**: am härtesten, der kürzeste Weg, am heißesten.\n⚠ Неправильные (те же корни, что в Komparativ): gut → am besten | viel → am meisten | gern → am liebsten | hoch → am höchsten | teuer → am teuersten | groß → am größten (без -e-!)", note: "С артиклем: der/die/das …ste — без am. Предикативно: am …sten. После t/d/s/sch/x/z → -este(n). Особые: am besten, am meisten, am liebsten, am größten (без -e-).", new: true, topics: ["grammar:adjectives", "new:new-rules"] },
  { id: "r0043", title: "Konjunktionen weil/dass/wenn — grammar/wordorder", topic: "grammar:wordorder", domen: "grammar", group: "wordorder", level: "A2", content_md: "Три частых союза придаточного — по вопросу легко выбрать:\n**Вопрос** | **Союз** | **Значение** | **Пример** |\nWarum? | **weil** | потому что (причина) | Ich gehe zum Bahnhof, weil ich meinen Freund abholen will. |\nWas? | **dass** | что (содержание) | Ich glaube, dass mein Freund heute kommt. |\nWann? | **wenn** | когда / если | Mein Freund ruft an, wenn er am Bahnhof ankommt. |\n💡 Во всех трёх глагол уходит в **конец** придаточного (см. правило о порядке глаголов в Nebensatz).\n⚠ Перед союзом — запятая.\n💡 **wenn** часто идёт в паре с **dann** в главном: Wenn das Wetter gut ist, dann gehen wir spazieren. (Если/когда …, то …)\n⚠ Не путай **wenn** (союз: если / когда) и **wann** (вопрос: когда?): Ich weiß nicht, wann er kommt.\n💡 wenn — «когда» (повторяющееся) и «если» (условие). Однократное «когда» в прошлом — als.", note: "weil — причина (Warum?), dass — содержание (Was?), wenn — время/условие (Wann?). Глагол в конец. wenn ↔ dann в главном. Не путать wenn (союз) и wann (вопрос). Als — однократное «когда» в прошлом.", new: true, topics: ["grammar:wordorder", "new:new-rules"] },
  { id: "r0038", title: "Оттенки: hell- / dunkel- + цвет (слитно)", topic: "grammar:adjectives", domen: "grammar", group: "adjectives", level: "A2", content_md: "Оттенок = **hell-** (светлый) или **dunkel-** (тёмный) + цвет, пишется **слитно**, одним словом.\n**основа + цвет** | **пример** |\nhell + braun | hellbraun (светло-коричневый) |\ndunkel + blau | dunkelblau (тёмно-синий) |\nhell + grün | hellgrün (светло-зелёный) |\ndunkel + rot | dunkelrot (тёмно-красный) |\n💡 Склоняются как обычные прилагательные: ein hellblaues Hemd, die dunkelgrüne Jacke.\n💡 Похоже образуется -farben / -farbig: cremefarben, silberfarbig.", note: "hell-/dunkel- + цвет пишется одним словом: hellblau, dunkelgrün, hellbraun. Склоняются как обычные прилагательные.", new: true, topics: ["grammar:adjectives", "new:new-rules"] },
  { id: "r0039", title: "Одежда: anhaben / tragen / angezogen sein (не «sein in»)", topic: "grammar:verbs", domen: "grammar", group: "verbs", level: "A2", content_md: "«Быть одетым в …» по-немецки НЕ передают через *Er ist in einer Jacke* — это калька с русского «он в». Используй один из трёх вариантов:\n**Конструкция** | **Пример** |\netw. **anhaben** (an … haben) | Er hat bunte Shorts an. |\netw. **tragen** | Er trägt bunte Shorts. |\n**angezogen sein** (как одет) | Er ist bunt angezogen. |\n⚠ *Er ist in …* — так не говорят.", note: "! Не используйте кальку с русского «он в …»: не Er ist in ..., а Er hat ... an / Er trägt ... / Er ist ... angezogen. anhaben отделяемый (hat ... an).", new: true, topics: ["grammar:verbs", "new:new-rules"] },
];

